    uint8_t buf[BLAKE3_BLOCK_LEN];
    uint8_t buf_len;
    uint8_t blocks_compressed;
    uint8_t flags;
} blake3_chunk_state;

typedef struct {
    uint32_t key[8];
    blake3_chunk_state chunk;
    uint8_t cv_stack_len;
    uint8_t cv_stack[(BLAKE3_MAX_DEPTH + 1) * 32];
} blake3_hasher;

void blake3_hasher_init(blake3_hasher *self);
