    const uint8_t *schedule = MSG_SCHEDULE[round];
    g(state, 0, 4,  8, 12, block_words[schedule[0]],  block_words[schedule[1]]);
    g(state, 1, 5,  9, 13, block_words[schedule[2]],  block_words[schedule[3]]);
    g(state, 2, 6, 10, 14, block_words[schedule[4]],  block_words[schedule[5]]);
    g(state, 3, 7, 11, 15, block_words[schedule[6]],  block_words[schedule[7]]);
    g(state, 0, 5, 10, 15, block_words[schedule[8]],  block_words[schedule[9]]);
    g(state, 1, 6, 11, 12, block_words[schedule[10]], block_words[schedule[11]]);
    g(state, 2, 7,  8, 13, block_words[schedule[12]], block_words[schedule[13]]);
    g(state, 3, 4,  9, 14, block_words[schedule[14]], block_words[schedule[15]]);
}

static void compress_pre(uint32_t state[16],
                         const uint32_t cv[8],
                         const uint8_t block[BLAKE3_BLOCK_LEN],
                         uint8_t block_len, uint64_t counter, uint8_t flags) {
    uint32_t block_words[16];
    for (size_t i = 0; i < 16; i++) {
        block_words[i] = load32(block + i * 4);
    }
    state[0] = cv[0]; state[1] = cv[1]; state[2] = cv[2]; state[3] = cv[3];
    state[4] = cv[4]; state[5] = cv[5]; state[6] = cv[6]; state[7] = cv[7];
    state[8]  = IV[0]; state[9]  = IV[1]; state[10] = IV[2]; state[11] = IV[3];
    state[12] = (uint32_t)counter;
    state[13] = (uint32_t)(counter >> 32);
    state[14] = (uint32_t)block_len;
    state[15] = (uint32_t)flags;
    for (size_t i = 0; i < 7; i++) {
        round_fn(state, block_words, i);
    }
}

/* Output a 32-byte chaining value (XOR the two halves and truncate). */
static void compress_in_place(uint32_t cv[8],
                              const uint8_t block[BLAKE3_BLOCK_LEN],
                              uint8_t block_len, uint64_t counter, uint8_t flags) {
    uint32_t state[16];
    compress_pre(state, cv, block, block_len, counter, flags);
    for (size_t i = 0; i < 8; i++) {
        cv[i] = state[i] ^ state[i + 8];
    }
}

/* Output a 64-byte block (for XOF). */
static void compress_xof(const uint32_t cv[8],
                         const uint8_t block[BLAKE3_BLOCK_LEN],
                         uint8_t block_len, uint64_t counter, uint8_t flags,
                         uint8_t out[64]) {
    uint32_t state[16];
    compress_pre(state, cv, block, block_len, counter, flags);
    for (size_t i = 0; i < 8; i++) {
        store32(&out[i * 4], state[i] ^ state[i + 8]);
        store32(&out[(i + 8) * 4], state[i + 8] ^ cv[i]);
    }
}

/* Chunk state */
static void chunk_state_init(blake3_chunk_state *self, const uint32_t key[8], uint8_t flags) {
    memcpy(self->cv, key, 32);
    self->chunk_counter = 0;
    memset(self->buf, 0, BLAKE3_BLOCK_LEN);
    self->buf_len = 0;
    self->blocks_compressed = 0;
    self->flags = flags;
}

static void chunk_state_reset(blake3_chunk_state *self, const uint32_t key[8], uint64_t chunk_counter) {
    memcpy(self->cv, key, 32);
    self->chunk_counter = chunk_counter;
    memset(self->buf, 0, BLAKE3_BLOCK_LEN);
    self->buf_len = 0;
    self->blocks_compressed = 0;
}

static size_t chunk_state_len(const blake3_chunk_state *self) {
    return ((size_t)self->blocks_compressed) * BLAKE3_BLOCK_LEN + (size_t)self->buf_len;
}

static uint8_t chunk_state_maybe_start_flag(const blake3_chunk_state *self) {
    return (self->blocks_compressed == 0) ? CHUNK_START : 0;
}

/* Output structure for finalization */
typedef struct {
    uint32_t input_cv[8];
    uint8_t block[BLAKE3_BLOCK_LEN];
    uint8_t block_len;
    uint64_t counter;
    uint8_t flags;
} output_t;

static output_t make_chunk_output(const blake3_chunk_state *self) {
    output_t out;
    memcpy(out.input_cv, self->cv, 32);
    memcpy(out.block, self->buf, BLAKE3_BLOCK_LEN);
    out.block_len = self->buf_len;
    out.counter = self->chunk_counter;
    out.flags = self->flags | chunk_state_maybe_start_flag(self) | CHUNK_END;
    return out;
}

static output_t make_parent_output(const uint8_t block[BLAKE3_BLOCK_LEN], const uint32_t key[8], uint8_t flags) {
    output_t out;
    memcpy(out.input_cv, key, 32);
    memcpy(out.block, block, BLAKE3_BLOCK_LEN);
    out.block_len = BLAKE3_BLOCK_LEN;
    out.counter = 0;
    out.flags = flags | PARENT;
    return out;
}

static void output_chaining_value(const output_t *self, uint8_t cv[32]) {
    uint32_t cv32[8];
    memcpy(cv32, self->input_cv, 32);
    compress_in_place(cv32, self->block, self->block_len, self->counter, self->flags);
    for (size_t i = 0; i < 8; i++) {
        store32(cv + i * 4, cv32[i]);
    }
}

static void output_root_bytes(const output_t *self, uint64_t seek, uint8_t *out, size_t out_len) {
    uint64_t output_block_counter = seek / 64;
    size_t offset_within_block = (size_t)(seek % 64);
    uint8_t wide_buf[64];
    while (out_len > 0) {
        compress_xof(self->input_cv, self->block, self->block_len,
                     output_block_counter, self->flags | ROOT, wide_buf);
        size_t available_bytes = 64 - offset_within_block;
        size_t memcpy_len = (out_len < available_bytes) ? out_len : available_bytes;
        memcpy(out, wide_buf + offset_within_block, memcpy_len);
        out += memcpy_len;
        out_len -= memcpy_len;
        output_block_counter += 1;
        offset_within_block = 0;
    }
}

static void chunk_state_update(blake3_chunk_state *self, const uint8_t *input, size_t input_len) {
    while (input_len > 0) {
        if (self->buf_len == BLAKE3_BLOCK_LEN) {
            uint8_t start_flag = chunk_state_maybe_start_flag(self);
            compress_in_place(self->cv, self->buf, BLAKE3_BLOCK_LEN,
                              self->chunk_counter, self->flags | start_flag);
            self->blocks_compressed += 1;
            self->buf_len = 0;
            memset(self->buf, 0, BLAKE3_BLOCK_LEN);
        }
        size_t want = BLAKE3_BLOCK_LEN - self->buf_len;
        size_t take = (input_len < want) ? input_len : want;
        memcpy(self->buf + self->buf_len, input, take);
        self->buf_len += (uint8_t)take;
        input += take;
        input_len -= take;
    }
}

static void hasher_init_base(blake3_hasher *self, const uint32_t key[8], uint8_t flags) {
    memcpy(self->key, key, 32);
    chunk_state_init(&self->chunk, key, flags);
    self->cv_stack_len = 0;
}

void blake3_hasher_init(blake3_hasher *self) {
    hasher_init_base(self, IV, 0);
}

void blake3_hasher_init_keyed(blake3_hasher *self, const uint8_t key[BLAKE3_KEY_LEN]) {
    uint32_t key_words[8];
    for (size_t i = 0; i < 8; i++) {
        key_words[i] = load32(key + i * 4);
    }
    hasher_init_base(self, key_words, KEYED_HASH);
}

void blake3_hasher_init_derive_key_raw(blake3_hasher *self, const void *context, size_t context_len) {
    blake3_hasher context_hasher;
    hasher_init_base(&context_hasher, IV, DERIVE_KEY_CONTEXT);
    blake3_hasher_update(&context_hasher, context, context_len);
    uint8_t context_key[BLAKE3_KEY_LEN];
    blake3_hasher_finalize(&context_hasher, context_key, BLAKE3_KEY_LEN);
    uint32_t context_key_words[8];
    for (size_t i = 0; i < 8; i++) {
        context_key_words[i] = load32(context_key + i * 4);
    }
    hasher_init_base(self, context_key_words, DERIVE_KEY_MATERIAL);
}

void blake3_hasher_init_derive_key(blake3_hasher *self, const char *context) {
    blake3_hasher_init_derive_key_raw(self, context, strlen(context));
}

/* push a single CV onto the stack */
static void hasher_push_cv(blake3_hasher *self, uint8_t new_cv[32], uint64_t chunk_counter) {
    /* Merge CVs from the right based on trailing zeros of (chunk_counter+1)
       chunk_counter here is the 0-indexed chunk that produced new_cv. */
    uint64_t post = chunk_counter + 1;
    while ((post & 1) == 0) {
        /* Pop top and merge with new_cv to form parent. */
        uint8_t parent_block[BLAKE3_BLOCK_LEN];
        memcpy(parent_block, self->cv_stack + (self->cv_stack_len - 1) * 32, 32);
        memcpy(parent_block + 32, new_cv, 32);
        self->cv_stack_len -= 1;
        output_t parent_out = make_parent_output(parent_block, self->key, self->chunk.flags);
        output_chaining_value(&parent_out, new_cv);
        post >>= 1;
    }
    memcpy(self->cv_stack + self->cv_stack_len * 32, new_cv, 32);
    self->cv_stack_len += 1;
}

void blake3_hasher_update(blake3_hasher *self, const void *input_void, size_t input_len) {
    const uint8_t *input = (const uint8_t *)input_void;
    while (input_len > 0) {
        if (chunk_state_len(&self->chunk) == BLAKE3_CHUNK_LEN) {
            /* Finalize the chunk and push to stack */
            output_t chunk_out = make_chunk_output(&self->chunk);
            uint8_t chunk_cv[32];
            output_chaining_value(&chunk_out, chunk_cv);
            uint64_t chunk_counter = self->chunk.chunk_counter;
            hasher_push_cv(self, chunk_cv, chunk_counter);
            chunk_state_reset(&self->chunk, self->key, chunk_counter + 1);
        }
        size_t want = BLAKE3_CHUNK_LEN - chunk_state_len(&self->chunk);
        size_t take = (input_len < want) ? input_len : want;
        chunk_state_update(&self->chunk, input, take);
        input += take;
        input_len -= take;
    }
}

void blake3_hasher_finalize(const blake3_hasher *self, uint8_t *out, size_t out_len) {
    blake3_hasher_finalize_seek(self, 0, out, out_len);
}

void blake3_hasher_finalize_seek(const blake3_hasher *self, uint64_t seek, uint8_t *out, size_t out_len) {
    if (out_len == 0) return;
    /* If there are no CVs in the stack yet, the chunk itself is the root */
    if (self->cv_stack_len == 0) {
        output_t out_struct = make_chunk_output(&self->chunk);
        output_root_bytes(&out_struct, seek, out, out_len);
        return;
    }
    /* Otherwise, we need to combine the chunk with the stack */
    /* Start with the current chunk as the rightmost CV */
    output_t out_struct;
    uint8_t cv[32];
    size_t cvs_remaining;
    if (chunk_state_len(&self->chunk) == 0) {
        /* The last chunk is empty - use the topmost CV in the stack as the rightmost */
        memcpy(cv, self->cv_stack + (self->cv_stack_len - 1) * 32, 32);
        cvs_remaining = self->cv_stack_len - 1;
    } else {
        output_t chunk_out = make_chunk_output(&self->chunk);
        output_chaining_value(&chunk_out, cv);
        cvs_remaining = self->cv_stack_len;
    }
    /* Now combine CVs from the right one by one */
    while (cvs_remaining > 0) {
        uint8_t parent_block[BLAKE3_BLOCK_LEN];
        memcpy(parent_block, self->cv_stack + (cvs_remaining - 1) * 32, 32);
        memcpy(parent_block + 32, cv, 32);
        if (cvs_remaining == 1) {
            /* This is the root - return the XOF output */
            out_struct = make_parent_output(parent_block, self->key, self->chunk.flags);
            output_root_bytes(&out_struct, seek, out, out_len);
            return;
        } else {
            output_t parent_out = make_parent_output(parent_block, self->key, self->chunk.flags);
            output_chaining_value(&parent_out, cv);
            cvs_remaining -= 1;
        }
    }
    /* Should not reach here, but handle just in case */
    memcpy(out, cv, out_len < 32 ? out_len : 32);
}

#include "blake3.h"
#include <stdio.h>
#include <string.h>
#include <stdlib.h>

static void hexprint(const uint8_t *data, size_t len) {
    for (size_t i = 0; i < len; i++) {
        printf("%02x", data[i]);
    }
    printf("\n");
}

static void test(const char *input, const char *expected) {
    blake3_hasher h;
    blake3_hasher_init(&h);
    blake3_hasher_update(&h, input, strlen(input));
    uint8_t out[32];
    blake3_hasher_finalize(&h, out, 32);
    char hex[65];
    for (int i = 0; i < 32; i++) {
        sprintf(hex + i * 2, "%02x", out[i]);
    }
    hex[64] = 0;
    if (strcmp(hex, expected) == 0) {
        printf("PASS: \"%s\" -> %s\n", input, hex);
    } else {
        printf("FAIL: \"%s\" -> %s (expected %s)\n", input, hex, expected);
    }
}

static void test_n(const uint8_t *input, size_t n, const char *label, const char *expected) {
    blake3_hasher h;
    blake3_hasher_init(&h);
    blake3_hasher_update(&h, input, n);
    uint8_t out[32];
    blake3_hasher_finalize(&h, out, 32);
    char hex[65];
    for (int i = 0; i < 32; i++) {
        sprintf(hex + i * 2, "%02x", out[i]);
    }
    hex[64] = 0;
    if (strcmp(hex, expected) == 0) {
        printf("PASS: %s -> %s\n", label, hex);
    } else {
        printf("FAIL: %s -> %s (expected %s)\n", label, hex, expected);
    }
}

static void test_keyed(const char *input, const uint8_t *key, const char *expected) {
    blake3_hasher h;
    blake3_hasher_init_keyed(&h, key);
    blake3_hasher_update(&h, input, strlen(input));
    uint8_t out[32];
    blake3_hasher_finalize(&h, out, 32);
    char hex[65];
    for (int i = 0; i < 32; i++) {
        sprintf(hex + i * 2, "%02x", out[i]);
    }
    hex[64] = 0;
    if (strcmp(hex, expected) == 0) {
        printf("PASS keyed: %s\n", hex);
    } else {
        printf("FAIL keyed: %s (expected %s)\n", hex, expected);
    }
}

static void test_dk(const char *input, const char *ctx, const char *expected) {
    blake3_hasher h;
    blake3_hasher_init_derive_key(&h, ctx);
    blake3_hasher_update(&h, input, strlen(input));
    uint8_t out[32];
    blake3_hasher_finalize(&h, out, 32);
    char hex[65];
    for (int i = 0; i < 32; i++) {
        sprintf(hex + i * 2, "%02x", out[i]);
    }
    hex[64] = 0;
    if (strcmp(hex, expected) == 0) {
        printf("PASS derive_key(%s): %s\n", ctx, hex);
    } else {
        printf("FAIL derive_key(%s): %s (expected %s)\n", ctx, hex, expected);
    }
}

int main(void) {
    test("", "af1349b9f5f9a1a6a0404dea36dcc9499bcb25c9adc112b7cc9a93cae41f3262");
    test("a", "17762fddd969a453925d65717ac3eea21320b66b54342fde15128d6caf21215f");
    test("ab", "2dc99999a6aaef3f20349d2ed4057a2b54419545dabb809e6381de1bad8337e2");
    test("abc", "6437b3ac38465133ffb63b75273a8db548c558465d79db03fd359c6cd5bd9d85");
    test("abcd", "8c9c9881805d1a847102d7a42e58b990d088dd88a84f7314d71c838107571f2b");
    test("hello", "ea8f163db38682925e4491c5e58d4bb3506ef8c14eb78a86e908c5624a67200f");
    test("hello world", "d74981efa70a0c880b8d8c1985d075dbcbf679b99a5f9914e5aaf96b831a9e24");
    test("world", "d7894ae9716d38d2dfad0ec55424ca321ee12453d51f1b3adeb77d0475ed988c");
    test("x", "3ae7d805f6789a6402acb70ad4096a85a56bf6804eaf25c0493ac697548d30b5");

    // Multi-chunk tests
    uint8_t *big = malloc(1048576);
    memset(big, 'A', 1048576);
    test_n(big, 1023, "1023*A", "b8f5edfc286965931110f8888dd37059077bfd91c6480f976212aca65b42748d");
    test_n(big, 1024, "1024*A", "f7314bcd4f08b945da46890d4abcbe9bd78905369461379ed5ab893eaccff236");
    test_n(big, 1025, "1025*A", "335c408d36141773e3edfff145793e88463ea12427aac0056976ab0cc5143a06");
    test_n(big, 2048, "2048*A", "b301a56f8d7092160e0afd7b32eebabfaa47a25a7d69c2a0129c7ac5fc5587b2");
    test_n(big, 65536, "65536*A", "0d8be3568c13195bed36fca3edd2c9631f184d475cd0b693492250cfc59d74a9");
    test_n(big, 1048576, "1048576*A", "4600ce32a5e74619c37eebd91fddb137aa1dd2c610350b71ef34432836cbba6a");

    // Keyed tests
    test_keyed("hello", (const uint8_t *)"0123456789abcdef0123456789abcdef", "14a41e9be55a5ced1b264d9f82dc0dcead598a4279710e28dadd0b0f5f4fcbdb");

    // Derive key tests
    test_dk("hello", "my context", "362d9eb1c4f619bf4a84a71f3928257a688ea94737a2b47ee6c73aff10e9b063");
    test_dk("hello", "", "200d39c57d23be8b0d94441dc3aa5ad4abec930f63b11b98a053f335717f4b83");

    // XOF tests - extended output
    blake3_hasher h;
    blake3_hasher_init(&h);
    blake3_hasher_update(&h, "x", 1);
    uint8_t out64[64];
    blake3_hasher_finalize(&h, out64, 64);
    printf("x*64 = ");
    hexprint(out64, 64);
    // Expected: 3ae7d805f6789a6402acb70ad4096a85a56bf6804eaf25c0493ac697548d30b5f3cf7f50f55e45ea9df4e25d1cd029d50d74a6eb533b36be19891788505a55e0

    // Seek test
    blake3_hasher_init(&h);
    blake3_hasher_update(&h, "x", 1);
    uint8_t out32[32];
    blake3_hasher_finalize_seek(&h, 32, out32, 32);
    printf("x@32 = ");
    hexprint(out32, 32);
    // Expected: f3cf7f50f55e45ea9df4e25d1cd029d50d74a6eb533b36be19891788505a55e0

    free(big);
    return 0;
}

