    uint8_t out64[64];
    blake3_hasher_finalize(&h, out64, 64);
    printf("x*64 = ");
    hexprint(out64, 64);
    // Expected: 3ae7d805f6789a6402acb70ad4096a85a56bf6804eaf25c0493ac697548d30b5f3cf7f50f55e45ea9df4e25d1cd029d50d74a6eb533b36be19891788505a55e0

    // Seek test
    blake3_hasher_init(&h);
    blake3_hasher_update(&h, "x", 1);
    uint8_t out32[32];
    blake3_hasher_finalize_seek(&h, 32, out32, 32);
    printf("x@32 = ");
    hexprint(out32, 32);
    // Expected: f3cf7f50f55e45ea9df4e25d1cd029d50d74a6eb533b36be19891788505a55e0

    free(big);
    return 0;
}

