#define VERSION_STRING "b3sum 1.8.4"

/* clap-like CLI parsing */

static int has_keyed = 0;
static int has_derive_key = 0;
static const char *derive_key_context = NULL;
static int has_length = 0;
static uint64_t length_val = 32;
static int has_seek = 0;
static uint64_t seek_val = 0;
static int has_num_threads = 0;
static uint64_t num_threads_val = 0;
static int has_no_mmap = 0;
static int has_no_names = 0;
static int has_raw = 0;
static int has_tag = 0;
static int has_check = 0;
static int has_quiet = 0;

#define MAX_FILES 65536
static const char *files[MAX_FILES];
static int num_files = 0;

static void usage_short(FILE *f) {
    fputs("Usage: executable [OPTIONS] [FILE]...\n", f);
}

static void usage_with(FILE *f, const char *with) {
    if (with) {
        fprintf(f, "Usage: executable %s\n", with);
    } else {
        usage_short(f);
    }
}

