static void clap_error(const char *err_msg, const char *tip, const char *usage_extra) {
    fprintf(stderr, "error: %s\n", err_msg);
    if (tip) {
        fprintf(stderr, "\n  tip: %s\n", tip);
    }
    fprintf(stderr, "\n");
    usage_with(stderr, usage_extra);
    fprintf(stderr, "\nFor more information, try '--help'.\n");
    exit(2);
}

/* Helpers for error usage based on currently-set flags */
static const char *current_usage_extra(void) {
    /* Based on what's been set so far, pick a usage extra */
    if (has_keyed) return "--keyed <FILE>...";
    if (has_derive_key) return "--derive-key <CONTEXT> [FILE]...";
    if (has_check) return "--check <FILE>...";
    if (has_tag) return "--tag <FILE>...";
    /* For --quiet without --check: --check --quiet <FILE>... */
    return NULL;
}

static int parse_u64(const char *s, uint64_t *out) {
    if (s[0] == 0) {
        return -1; /* empty */
    }
    if (s[0] == '-') {
        return -2; /* negative not allowed for u64 - but we treat as invalid */
    }
    uint64_t r = 0;
    for (const char *p = s; *p; p++) {
        if (*p < '0' || *p > '9') {
            return -3; /* invalid digit */
        }
        uint64_t d = (uint64_t)(*p - '0');
        if (r > (UINT64_MAX - d) / 10) {
            return -4; /* overflow */
        }
        r = r * 10 + d;
    }
    *out = r;
    return 0;
}

static const char *error_for_u64_parse(int code) {
    switch (code) {
        case -1: return "cannot parse integer from empty string";
        case -2: return "invalid digit found in string";
        case -3: return "invalid digit found in string";
        case -4: return "number too large to fit in target type";
        default: return "unknown error";
    }
}

static int is_long_flag(const char *arg, const char *flag) {
    /* matches --flag exactly, or --flag=value (returns 1 in both cases) */
    size_t fl = strlen(flag);
    if (strncmp(arg, flag, fl) != 0) return 0;
    if (arg[fl] == 0) return 1; /* exact match */
    if (arg[fl] == '=') return 2; /* with value */
    return 0;
}

static void set_dup_error(const char *flagname) {
    char buf[256];
    snprintf(buf, sizeof(buf), "the argument '%s' cannot be used multiple times", flagname);
    clap_error(buf, NULL, NULL);
}

static void set_conflict_error(const char *a, const char *b) {
    char buf[256];
    snprintf(buf, sizeof(buf), "the argument '%s' cannot be used with '%s'", a, b);
    clap_error(buf, NULL, current_usage_extra());
}

static void parse_args(int argc, char **argv) {
    int positional_only = 0;
    for (int i = 1; i < argc; i++) {
        const char *a = argv[i];
        if (positional_only) {
            if (num_files >= MAX_FILES) {
                fprintf(stderr, "Error: too many files\n");
                exit(2);
            }
            files[num_files++] = a;
            continue;
        }
        if (strcmp(a, "--") == 0) {
            positional_only = 1;
            continue;
        }
        if (strcmp(a, "--help") == 0) {
            print_help_long();
            exit(0);
        }
        if (strcmp(a, "-h") == 0) {
            print_help_short();
            exit(0);
        }
        if (strcmp(a, "--version") == 0 || strcmp(a, "-V") == 0) {
            printf("%s\n", VERSION_STRING);
            exit(0);
        }

        /* Boolean flags */
        if (strcmp(a, "--keyed") == 0) {
            if (has_keyed) set_dup_error("--keyed");
            has_keyed = 1;
            if (has_derive_key) set_conflict_error("--keyed", "--derive-key <CONTEXT>");
            if (has_check) set_conflict_error("--check", "--keyed");
            continue;
        }
        if (strcmp(a, "--no-mmap") == 0) {
            if (has_no_mmap) set_dup_error("--no-mmap");
            has_no_mmap = 1;
            continue;
        }
        if (strcmp(a, "--no-names") == 0) {
            if (has_no_names) set_dup_error("--no-names");
            has_no_names = 1;
            if (has_check) set_conflict_error("--check", "--no-names");
            continue;
        }
        if (strcmp(a, "--raw") == 0) {
            if (has_raw) set_dup_error("--raw");
            has_raw = 1;
            if (has_check) set_conflict_error("--check", "--raw");
            continue;
        }
        if (strcmp(a, "--tag") == 0) {
            if (has_tag) set_dup_error("--tag");
            has_tag = 1;
            if (has_check) set_conflict_error("--check", "--tag");
            continue;
        }
        if (strcmp(a, "--check") == 0 || strcmp(a, "-c") == 0) {
            if (has_check) set_dup_error("--check");
            has_check = 1;
            if (has_tag) set_conflict_error("--check", "--tag");
            if (has_raw) set_conflict_error("--check", "--raw");
            if (has_keyed) set_conflict_error("--check", "--keyed");
            if (has_derive_key) set_conflict_error("--check", "--derive-key <CONTEXT>");
            if (has_no_names) set_conflict_error("--check", "--no-names");
            if (has_length) set_conflict_error("--check", "--length <LEN>");
            continue;
        }
        if (strcmp(a, "--quiet") == 0) {
            if (has_quiet) set_dup_error("--quiet");
            has_quiet = 1;
            continue;
        }

        /* Options that take a value */
        if (strcmp(a, "--derive-key") == 0) {
            if (has_derive_key) set_dup_error("--derive-key <CONTEXT>");
            if (i + 1 >= argc) {
                clap_error("a value is required for '--derive-key <CONTEXT>' but none was supplied", NULL, NULL);
            }
            has_derive_key = 1;
            derive_key_context = argv[++i];
            if (has_keyed) set_conflict_error("--derive-key <CONTEXT>", "--keyed");
            if (has_check) set_conflict_error("--check", "--derive-key <CONTEXT>");
            continue;
        }
        if (strncmp(a, "--derive-key=", 13) == 0) {
            if (has_derive_key) set_dup_error("--derive-key <CONTEXT>");
            has_derive_key = 1;
            derive_key_context = a + 13;
            if (has_keyed) set_conflict_error("--derive-key <CONTEXT>", "--keyed");
            if (has_check) set_conflict_error("--check", "--derive-key <CONTEXT>");
            continue;
        }

        if (strcmp(a, "--length") == 0 || strcmp(a, "-l") == 0) {
            if (has_length) set_dup_error("--length <LEN>");
            if (i + 1 >= argc) {
                clap_error("a value is required for '--length <LEN>' but none was supplied", NULL, NULL);
            }
            has_length = 1;
            const char *val = argv[++i];
            int rc = parse_u64(val, &length_val);
            if (rc != 0) {
                char buf[256];
                snprintf(buf, sizeof(buf), "invalid value '%s' for '--length <LEN>': %s", val, error_for_u64_parse(rc));
                clap_error(buf, NULL, NULL);
            }
            if (has_check) set_conflict_error("--check", "--length <LEN>");
            continue;
        }
        if (strncmp(a, "--length=", 9) == 0) {
            if (has_length) set_dup_error("--length <LEN>");
            has_length = 1;
            const char *val = a + 9;
            int rc = parse_u64(val, &length_val);
            if (rc != 0) {
                char buf[256];
                snprintf(buf, sizeof(buf), "invalid value '%s' for '--length <LEN>': %s", val, error_for_u64_parse(rc));
                clap_error(buf, NULL, NULL);
            }
            if (has_check) set_conflict_error("--check", "--length <LEN>");
            continue;
        }
        if (strncmp(a, "-l", 2) == 0 && a[2] != 0) {
            /* -lN form */
            if (has_length) set_dup_error("--length <LEN>");
            has_length = 1;
            const char *val = a + 2;
            int rc = parse_u64(val, &length_val);
            if (rc != 0) {
                char buf[256];
                snprintf(buf, sizeof(buf), "invalid value '%s' for '--length <LEN>': %s", val, error_for_u64_parse(rc));
                clap_error(buf, NULL, NULL);
            }
            if (has_check) set_conflict_error("--check", "--length <LEN>");
            continue;
        }

        if (strcmp(a, "--seek") == 0) {
            if (has_seek) set_dup_error("--seek <SEEK>");
            if (i + 1 >= argc) {
                clap_error("a value is required for '--seek <SEEK>' but none was supplied", NULL, NULL);
            }
            has_seek = 1;
            const char *val = argv[++i];
            int rc = parse_u64(val, &seek_val);
            if (rc != 0) {
                char buf[256];
                snprintf(buf, sizeof(buf), "invalid value '%s' for '--seek <SEEK>': %s", val, error_for_u64_parse(rc));
                clap_error(buf, NULL, NULL);
            }
            continue;
        }
        if (strncmp(a, "--seek=", 7) == 0) {
            if (has_seek) set_dup_error("--seek <SEEK>");
            has_seek = 1;
            const char *val = a + 7;
            int rc = parse_u64(val, &seek_val);
            if (rc != 0) {
                char buf[256];
                snprintf(buf, sizeof(buf), "invalid value '%s' for '--seek <SEEK>': %s", val, error_for_u64_parse(rc));
                clap_error(buf, NULL, NULL);
            }
            continue;
        }

        if (strcmp(a, "--num-threads") == 0) {
            if (has_num_threads) set_dup_error("--num-threads <NUM>");
            if (i + 1 >= argc) {
                clap_error("a value is required for '--num-threads <NUM>' but none was supplied", NULL, NULL);
            }
            has_num_threads = 1;
            const char *val = argv[++i];
            int rc = parse_u64(val, &num_threads_val);
            if (rc != 0) {
                char buf[256];
                snprintf(buf, sizeof(buf), "invalid value '%s' for '--num-threads <NUM>': %s", val, error_for_u64_parse(rc));
                clap_error(buf, NULL, NULL);
            }
            continue;
        }
        if (strncmp(a, "--num-threads=", 14) == 0) {
            if (has_num_threads) set_dup_error("--num-threads <NUM>");
            has_num_threads = 1;
            const char *val = a + 14;
            int rc = parse_u64(val, &num_threads_val);
            if (rc != 0) {
                char buf[256];
                snprintf(buf, sizeof(buf), "invalid value '%s' for '--num-threads <NUM>': %s", val, error_for_u64_parse(rc));
                clap_error(buf, NULL, NULL);
            }
            continue;
        }

        /* If looks like an option but unknown: error */
        if (a[0] == '-' && a[1] != 0) {
            char buf[256];
            snprintf(buf, sizeof(buf), "unexpected argument '%s' found", a);
            char tip[256];
            snprintf(tip, sizeof(tip), "to pass '%s' as a value, use '-- %s'", a, a);
            const char *usage_extra = (num_files > 0) ? "<FILE>..." : current_usage_extra();
            /* Match the reference: tip line is shown, with usage */
            fprintf(stderr, "error: %s\n", buf);
            fprintf(stderr, "\n  tip: %s\n", tip);
            fprintf(stderr, "\n");
            usage_with(stderr, usage_extra);
            fprintf(stderr, "\nFor more information, try '--help'.\n");
            exit(2);
        }

        /* Positional */
        if (num_files >= MAX_FILES) {
            fprintf(stderr, "Error: too many files\n");
            exit(2);
        }
        files[num_files++] = a;
    }

    /* Post-parse validation */
    if (has_quiet && !has_check) {
        clap_error("the following required arguments were not provided:\n  --check",
                   NULL, "--check --quiet <FILE>...");
    }
    if (has_keyed && num_files == 0) {
        clap_error("the following required arguments were not provided:\n  <FILE>...",
                   NULL, "--keyed <FILE>...");
    }
}

/* I/O helpers */

static int read_all(int fd, uint8_t *buf, size_t max, size_t *actual) {
    size_t total = 0;
    while (total < max) {
        ssize_t r = read(fd, buf + total, max - total);
        if (r < 0) {
            if (errno == EINTR) continue;
            return -1;
        }
        if (r == 0) break;
        total += (size_t)r;
    }
    *actual = total;
    return 0;
}

/* Read at most 32 bytes for keyed mode, error if more available or less */
static int read_key_stdin(uint8_t key[32]) {
    size_t total = 0;
    while (total < 32) {
        ssize_t r = read(STDIN_FILENO, key + total, 32 - total);
        if (r < 0) {
            if (errno == EINTR) continue;
            fprintf(stderr, "Error: %s (os error %d)\n", strerror(errno), errno);
            return -1;
        }
        if (r == 0) {
            fprintf(stderr, "Error: expected 32 key bytes from stdin, found %zu\n", total);
            return -1;
        }
        total += (size_t)r;
    }
    /* Now try to read one more byte to check if there are more */
    uint8_t extra;
    ssize_t r;
    do {
        r = read(STDIN_FILENO, &extra, 1);
    } while (r < 0 && errno == EINTR);
    if (r > 0) {
        fprintf(stderr, "Error: read more than 32 key bytes from stdin\n");
        return -1;
    }
    return 0;
}

/* Hash a file or stdin and write the hash bytes to out (length out_len) */
static int hash_input(const char *path, blake3_hasher *base, uint8_t *out, size_t out_len, uint64_t seek) {
    int fd;
    if (path == NULL || strcmp(path, "-") == 0) {
        fd = STDIN_FILENO;
    } else {
        fd = open(path, O_RDONLY);
        if (fd < 0) {
            return -errno;
        }
        /* Detect directory */
        struct stat st;
        if (fstat(fd, &st) == 0 && S_ISDIR(st.st_mode)) {
            close(fd);
            return -EISDIR;
        }
    }

    blake3_hasher h = *base;
    uint8_t buf[65536];
    while (1) {
        ssize_t r = read(fd, buf, sizeof(buf));
        if (r < 0) {
            int e = errno;
            if (e == EINTR) continue;
            if (fd != STDIN_FILENO) close(fd);
            return -e;
        }
        if (r == 0) break;
        blake3_hasher_update(&h, buf, (size_t)r);
    }
    if (fd != STDIN_FILENO) close(fd);
    blake3_hasher_finalize_seek(&h, seek, out, out_len);
    return 0;
}

/* Output filename escape - returns 1 if escaped, 0 otherwise */
static int filename_needs_escape(const char *s) {
    for (const char *p = s; *p; p++) {
        if (*p == '\\' || *p == '\n' || *p == '\r') return 1;
    }
    return 0;
}

/* Write escaped filename to file */
static void write_escaped(FILE *f, const char *s) {
    for (const char *p = s; *p; p++) {
        if (*p == '\\') fputs("\\\\", f);
        else if (*p == '\n') fputs("\\n", f);
        else if (*p == '\r') fputs("\\r", f);
        else fputc(*p, f);
    }
}

static void print_hex(FILE *f, const uint8_t *data, size_t len) {
    static const char hex[] = "0123456789abcdef";
    for (size_t i = 0; i < len; i++) {
        fputc(hex[(data[i] >> 4) & 0xf], f);
        fputc(hex[data[i] & 0xf], f);
    }
}

static int write_output_for_file(const char *path, const uint8_t *hash, size_t hash_len, int is_stdin_dash) {
    const char *display = is_stdin_dash ? "-" : path;
    int needs_esc = filename_needs_escape(display);
    if (has_no_names) {
        /* Just the hash + newline */
        print_hex(stdout, hash, hash_len);
        fputc('\n', stdout);
    } else if (has_tag) {
        /* BSD format: [\\]BLAKE3 (filename) = hash */
        if (needs_esc) fputc('\\', stdout);
        fputs("BLAKE3 (", stdout);
        write_escaped(stdout, display);
        fputs(") = ", stdout);
        print_hex(stdout, hash, hash_len);
        fputc('\n', stdout);
    } else {
        /* Default: [\\]hash  filename */
        if (needs_esc) fputc('\\', stdout);
        print_hex(stdout, hash, hash_len);
        fputs("  ", stdout);
        write_escaped(stdout, display);
        fputc('\n', stdout);
    }
    return 0;
}

/* Constants for error -> message conversion */
static const char *errno_str(int e) {
    return strerror(e);
}

/* Check mode line parsing */
typedef struct {
    char *filename;       /* Allocated; may have escapes processed */
    uint8_t hash[32];     /* Expected hash */
    int valid;
    const char *error;    /* If invalid, the error message */
    int was_escaped;      /* Original line had \ prefix */
} check_line_t;

/* Parse a single hex digit; return -1 if not lowercase hex */
static int hex_digit(char c) {
    if (c >= '0' && c <= '9') return c - '0';
    if (c >= 'a' && c <= 'f') return c - 'a' + 10;
    return -1;
}

/* Unescape filename in-place; returns 0 on success, -1 on bad escape */
static int unescape_filename(char *s) {
    char *r = s, *w = s;
    while (*r) {
        if (*r == '\\') {
            r++;
            if (*r == 'n') { *w++ = '\n'; r++; }
            else if (*r == 'r') { *w++ = '\r'; r++; }
            else if (*r == '\\') { *w++ = '\\'; r++; }
            else { /* invalid escape - silently keep? or error? */ return -1; }
        } else {
            *w++ = *r++;
        }
    }
    *w = 0;
    return 0;
}

/* Parse a check line - returns malloc'd structure */
static void parse_check_line(char *line, check_line_t *cl) {
    cl->filename = NULL;
    cl->valid = 0;
    cl->error = NULL;
    cl->was_escaped = 0;

    /* Empty? */
    if (line[0] == 0) {
        cl->error = "Empty line";
        return;
    }

    /* Check for leading backslash (escape marker) */
    int escaped = 0;
    char *p = line;
    if (p[0] == '\\') {
        escaped = 1;
        p++;
    }
    cl->was_escaped = escaped;

    /* Try BSD format first: "BLAKE3 (FILENAME) = HASH" */
    if (strncmp(p, "BLAKE3 (", 8) == 0) {
        /* Find ") = " from the END */
        size_t plen = strlen(p);
        if (plen >= 8 + 5) {
            /* Look for last occurrence of ") = " */
            ssize_t pos = -1;
            for (ssize_t i = (ssize_t)plen - 4; i >= 8; i--) {
                if (p[i] == ')' && p[i+1] == ' ' && p[i+2] == '=' && p[i+3] == ' ') {
                    pos = i;
                    break;
                }
            }
            if (pos > 0) {
                /* Filename is p[8..pos], hash is p[pos+4..] */
                char *fname = malloc((size_t)(pos - 8) + 1);
                if (!fname) {
                    cl->error = "Memory allocation failed";
                    return;
                }
                memcpy(fname, p + 8, (size_t)(pos - 8));
                fname[pos - 8] = 0;

                const char *hash_str = p + pos + 4;
                size_t hash_len = strlen(hash_str);
                if (hash_len != 64) {
                    free(fname);
                    cl->error = "Invalid hash length";
                    return;
                }
                /* Parse hash */
                for (int i = 0; i < 32; i++) {
                    int hi = hex_digit(hash_str[i * 2]);
                    int lo = hex_digit(hash_str[i * 2 + 1]);
                    if (hi < 0 || lo < 0) {
                        free(fname);
                        cl->error = "Invalid hex";
                        return;
                    }
                    cl->hash[i] = (uint8_t)((hi << 4) | lo);
                }
                /* Unescape filename if escaped */
                if (escaped) {
                    if (unescape_filename(fname) < 0) {
                        free(fname);
                        cl->error = "Invalid check line format";
                        return;
                    }
                }
                if (fname[0] == 0) {
                    free(fname);
                    cl->error = "empty file path";
                    return;
                }
                cl->filename = fname;
                cl->valid = 1;
                return;
            }
        }
        /* Falls through to non-BSD parse */
    }

    /* Standard format: "HASH  FILENAME" (exactly 2 spaces) */
    /* Find "  " (double space) in the line */
    char *sep = strstr(p, "  ");
    if (!sep) {
        cl->error = "Invalid check line format";
        return;
    }
    size_t hash_len = (size_t)(sep - p);
    if (hash_len != 64) {
        cl->error = "Invalid hash length";
        return;
    }
    /* Parse hash */
    for (int i = 0; i < 32; i++) {
        int hi = hex_digit(p[i * 2]);
        int lo = hex_digit(p[i * 2 + 1]);
        if (hi < 0 || lo < 0) {
            cl->error = "Invalid hex";
            return;
        }
        cl->hash[i] = (uint8_t)((hi << 4) | lo);
    }
    char *fname_start = sep + 2;
    size_t fnlen = strlen(fname_start);
    char *fname = malloc(fnlen + 1);
    if (!fname) {
        cl->error = "Memory allocation failed";
        return;
    }
    memcpy(fname, fname_start, fnlen + 1);
    if (escaped) {
        if (unescape_filename(fname) < 0) {
            free(fname);
            cl->error = "Invalid check line format";
            return;
        }
    }
    if (fname[0] == 0) {
        free(fname);
        cl->error = "empty file path";
        return;
    }
    cl->filename = fname;
    cl->valid = 1;
}

/* Read a file fully into memory, returns 0 on success, -errno on fail */
static int read_file_to_buf(const char *path, uint8_t **out_buf, size_t *out_len) {
    int fd;
    if (path == NULL || strcmp(path, "-") == 0) {
        fd = STDIN_FILENO;
    } else {
        fd = open(path, O_RDONLY);
        if (fd < 0) return -errno;
        struct stat st;
        if (fstat(fd, &st) == 0 && S_ISDIR(st.st_mode)) {
            close(fd);
            return -EISDIR;
        }
    }
    size_t cap = 65536, total = 0;
    uint8_t *buf = malloc(cap);
    if (!buf) {
        if (fd != STDIN_FILENO) close(fd);
        return -ENOMEM;
    }
    while (1) {
        if (total == cap) {
            cap *= 2;
            uint8_t *nb = realloc(buf, cap);
            if (!nb) { free(buf); if (fd != STDIN_FILENO) close(fd); return -ENOMEM; }
            buf = nb;
        }
        ssize_t r = read(fd, buf + total, cap - total);
        if (r < 0) {
            int e = errno;
            if (e == EINTR) continue;
            free(buf);
            if (fd != STDIN_FILENO) close(fd);
            return -e;
        }
        if (r == 0) break;
        total += (size_t)r;
    }
    if (fd != STDIN_FILENO) close(fd);
    *out_buf = buf;
    *out_len = total;
    return 0;
}

/* Strip trailing \r's from the in-place line */
static void strip_trailing_cr(char *line) {
    size_t len = strlen(line);
    while (len > 0 && line[len - 1] == '\r') {
        line[--len] = 0;
    }
}

/* check_one_file processes one checkfile and updates fail count */
static int check_one_file(const char *path, uint64_t *fail_count) {
    uint8_t *buf;
    size_t buflen;
    int rc = read_file_to_buf(path, &buf, &buflen);
    if (rc < 0) {
        fprintf(stderr, "Error: %s (os error %d)\n", strerror(-rc), -rc);
        return -1;
    }
    /* Split into lines by \n */
    size_t i = 0;
    while (i < buflen) {
        size_t line_start = i;
        while (i < buflen && buf[i] != '\n') i++;
        size_t line_end = i;
        if (i < buflen) i++; /* skip \n */
        /* Copy line into temp buffer */
        size_t llen = line_end - line_start;
        char *line = malloc(llen + 1);
        if (!line) {
            fprintf(stderr, "Error: out of memory\n");
            free(buf);
            return -1;
        }
        memcpy(line, buf + line_start, llen);
        line[llen] = 0;
        /* Strip trailing \r's */
        strip_trailing_cr(line);

        check_line_t cl;
        parse_check_line(line, &cl);

        if (!cl.valid) {
            fprintf(stderr, "b3sum: %s\n", cl.error);
            (*fail_count)++;
            free(line);
            if (cl.filename) free(cl.filename);
            continue;
        }

        /* Compute hash of the referenced file */
        blake3_hasher base;
        blake3_hasher_init(&base);
        uint8_t actual[32];
        int hr = hash_input(cl.filename, &base, actual, 32, 0);

        if (hr < 0) {
            /* File error */
            if (cl.was_escaped) fputc('\\', stdout);
            for (const char *p = cl.filename; *p; p++) {
                if (*p == '\\') fputs("\\\\", stdout);
                else if (*p == '\n') fputs("\\n", stdout);
                else if (*p == '\r') fputs("\\r", stdout);
                else fputc(*p, stdout);
            }
            fprintf(stdout, ": FAILED (%s (os error %d))\n", strerror(-hr), -hr);
            (*fail_count)++;
        } else if (memcmp(actual, cl.hash, 32) != 0) {
            if (cl.was_escaped) fputc('\\', stdout);
            for (const char *p = cl.filename; *p; p++) {
                if (*p == '\\') fputs("\\\\", stdout);
                else if (*p == '\n') fputs("\\n", stdout);
                else if (*p == '\r') fputs("\\r", stdout);
                else fputc(*p, stdout);
            }
            fputs(": FAILED\n", stdout);
            (*fail_count)++;
        } else {
            if (!has_quiet) {
                if (cl.was_escaped) fputc('\\', stdout);
                for (const char *p = cl.filename; *p; p++) {
                    if (*p == '\\') fputs("\\\\", stdout);
                    else if (*p == '\n') fputs("\\n", stdout);
                    else if (*p == '\r') fputs("\\r", stdout);
                    else fputc(*p, stdout);
                }
                fputs(": OK\n", stdout);
            }
        }
        free(cl.filename);
        free(line);
    }
    free(buf);
    return 0;
}

static int do_check(void) {
    uint64_t fail_count = 0;
    int err_in_files = 0;
    if (num_files == 0) {
        check_one_file("-", &fail_count);
    } else {
        for (int i = 0; i < num_files; i++) {
            int rc = check_one_file(files[i], &fail_count);
            if (rc < 0) {
                err_in_files = 1;
                break;
            }
        }
    }
    if (fail_count > 0) {
        if (fail_count == 1) {
            fprintf(stderr, "b3sum: WARNING: 1 computed checksum did NOT match\n");
        } else {
            fprintf(stderr, "b3sum: WARNING: %" PRIu64 " computed checksums did NOT match\n", fail_count);
        }
        return 1;
    }
    if (err_in_files) return 1;
    return 0;
}

static int do_hash(void) {
    /* Setup the base hasher */
    blake3_hasher base;
    if (has_keyed) {
        uint8_t key[32];
        if (read_key_stdin(key) < 0) return 1;
        blake3_hasher_init_keyed(&base, key);
    } else if (has_derive_key) {
        blake3_hasher_init_derive_key(&base, derive_key_context);
    } else {
        blake3_hasher_init(&base);
    }

    /* Determine output buffer size */
    /* Note: for very large length_val we might want to stream, but here we allocate */
    size_t out_len = (size_t)length_val;
    /* Cap allocation - if length is huge, we'll need streaming */
    /* For now, allocate as needed but be wary of huge sizes */
    uint8_t *out = NULL;
    if (out_len > 0) {
        /* For raw mode with single file, allocate; otherwise we need to print as hex */
        /* Allocate in chunks if too large */
    }

    /* Special validation for --raw */
    if (has_raw) {
        int input_count = (num_files == 0) ? 1 : num_files;
        if (input_count > 1) {
            fprintf(stderr, "Error: Only one filename can be provided when using --raw\n");
            return 1;
        }
    }

    int any_error = 0;
    if (num_files == 0) {
        /* Read from stdin */
        if (has_keyed) {
            /* shouldn't happen as we error out earlier if no files in keyed mode */
        }
        /* Compute hash */
        out = malloc(out_len > 0 ? out_len : 1);
        if (!out) { fprintf(stderr, "Error: out of memory\n"); return 1; }
        int rc = hash_input("-", &base, out, out_len, seek_val);
        if (rc < 0) {
            fprintf(stderr, "b3sum: -: %s (os error %d)\n", strerror(-rc), -rc);
            free(out);
            return 1;
        }
        if (has_raw) {
            fwrite(out, 1, out_len, stdout);
        } else {
            write_output_for_file(NULL, out, out_len, 1);
        }
        free(out);
    } else {
        for (int i = 0; i < num_files; i++) {
            const char *path = files[i];
            if (has_keyed && strcmp(path, "-") == 0) {
                fprintf(stderr, "b3sum: -: Cannot open `-` in keyed mode\n");
                any_error = 1;
                continue;
            }
            int is_stdin_dash = (strcmp(path, "-") == 0);
            out = malloc(out_len > 0 ? out_len : 1);
            if (!out) { fprintf(stderr, "Error: out of memory\n"); return 1; }
            int rc = hash_input(path, &base, out, out_len, seek_val);
            if (rc < 0) {
                fprintf(stderr, "b3sum: %s: %s (os error %d)\n", path, strerror(-rc), -rc);
                free(out);
                any_error = 1;
                continue;
            }
            if (has_raw) {
                fwrite(out, 1, out_len, stdout);
            } else {
                write_output_for_file(path, out, out_len, is_stdin_dash);
            }
            free(out);
        }
    }
    return any_error ? 1 : 0;
}

int main(int argc, char **argv) {
    /* Ignore SIGPIPE - we want to exit cleanly */
    signal(SIGPIPE, SIG_DFL);
    parse_args(argc, argv);
    if (has_check) {
        return do_check();
    }
    return do_hash();
}

